INSERT INTO `mdl_notifications` VALUES
(1,-10,2,'New sign in to your New Site account','Hi Admin User,\n\nYour New Site account was just signed in to from a new device.\n\n	* Your account: admin user@example.com\n	* Tuesday, 17 March 2026, 11:30 AM\n	* Device: Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36\n(KHTML, like Gecko) Chrome/146.0.0.0 Safari/537.36\n	* IP: 172.18.0.1\n\nIf this was you, then you don\'t need to do anything.\n\nIf you don\'t recognise this activity, please change your password [1].\n\n\nLinks:\n------\n[1] http://127.0.0.1:8080/login/change_password.php\n',1,'<p>Hi Admin User,</p>\n<p>Your New Site account was just signed in to from a new device.</p>\n<ul>\n<li>Your account: admin user@example.com</li>\n<li>Tuesday, 17 March 2026, 11:30 AM</li>\n<li>Device:  Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/146.0.0.0 Safari/537.36</li>\n<li>IP: 172.18.0.1</li>\n</ul>\n<p>If this was you, then you don\'t need to do anything.</p>\n<p>If you don\'t recognise this activity, please <a href=\"http://127.0.0.1:8080/login/change_password.php\">change your password</a>.</p>','Your admin account was just signed in to from a new device.','moodle','newlogin',NULL,NULL,1774716279,1773747012,'{\"notificationiconurl\":\"http:\\/\\/127.0.0.1:8080\\/theme\\/image.php\\/boost\\/core\\/1773746936\\/u\\/f1\",\"courseid\":\"1\"}'),
(2,2,3,'Welcome to Програмування','Dear Ivan Ivanenko, you are enrolled in the course Програмування.',4,'Dear Ivan Ivanenko, you are enrolled in the course Програмування.',NULL,'moodle','enrolcoursewelcomemessage','http://localhost/user/view.php?id=3&amp;course=3','Програмування',NULL,1773763953,NULL),
(3,2,3,'Admin User has given feedback for assignment Лабораторна робота 1','prog1 -> Assignment -> Лабораторна робота 1\n---------------------------------------------------------------------\nAdmin User has posted some feedback on your\nassignment submission for \'Лабораторна робота 1\'\n\nYou can see it appended to your assignment submission:\n\n    http://127.0.0.1:8080/mod/assign/view.php?id=3\n\n---------------------------------------------------------------------\n',2,'<p><font face=\"sans-serif\"><a href=\"http://127.0.0.1:8080/course/view.php?id=3\">prog1</a> -><a href=\"http://127.0.0.1:8080/mod/assign/index.php?id=3\">Assignment</a> -><a href=\"http://127.0.0.1:8080/mod/assign/view.php?id=3\">Лабораторна робота 1</a></font></p><hr /><font face=\"sans-serif\"><p>Admin User has posted some feedback on your\nassignment submission for \'<i>Лабораторна робота 1</i>\'<br /><br />\nYou can see it appended to your <a href=\"http://127.0.0.1:8080/mod/assign/view.php?id=3\">assignment submission</a>.</p></font><hr />','Admin User has given feedback for assignment Лабораторна робота 1','mod_assign','assign_notification','http://127.0.0.1:8080/mod/assign/view.php?id=3','Лабораторна робота 1',NULL,1773764041,'{\"cmid\":\"3\",\"instance\":\"1\",\"messagetype\":\"feedbackavailable\",\"blindmarking\":false,\"uniqueidforuser\":0,\"notificationiconurl\":\"http:\\/\\/127.0.0.1:8080\\/theme\\/image.php\\/boost\\/core\\/1773746936\\/u\\/f1\",\"courseid\":\"3\"}'),
(4,2,3,'Admin User has given feedback for assignment Лабораторна робота 2','prog1 -> Assignment -> Лабораторна робота 2\n---------------------------------------------------------------------\nAdmin User has posted some feedback on your\nassignment submission for \'Лабораторна робота 2\'\n\nYou can see it appended to your assignment submission:\n\n    http://127.0.0.1:8080/mod/assign/view.php?id=4\n\n---------------------------------------------------------------------\n',2,'<p><font face=\"sans-serif\"><a href=\"http://127.0.0.1:8080/course/view.php?id=3\">prog1</a> -><a href=\"http://127.0.0.1:8080/mod/assign/index.php?id=3\">Assignment</a> -><a href=\"http://127.0.0.1:8080/mod/assign/view.php?id=4\">Лабораторна робота 2</a></font></p><hr /><font face=\"sans-serif\"><p>Admin User has posted some feedback on your\nassignment submission for \'<i>Лабораторна робота 2</i>\'<br /><br />\nYou can see it appended to your <a href=\"http://127.0.0.1:8080/mod/assign/view.php?id=4\">assignment submission</a>.</p></font><hr />','Admin User has given feedback for assignment Лабораторна робота 2','mod_assign','assign_notification','http://127.0.0.1:8080/mod/assign/view.php?id=4','Лабораторна робота 2',NULL,1773764941,'{\"cmid\":\"4\",\"instance\":\"2\",\"messagetype\":\"feedbackavailable\",\"blindmarking\":false,\"uniqueidforuser\":0,\"notificationiconurl\":\"http:\\/\\/127.0.0.1:8080\\/theme\\/image.php\\/boost\\/core\\/1773746936\\/u\\/f1\",\"courseid\":\"3\"}'),
(5,2,2,'Moodle updates are available (http://127.0.0.1:8080)','Update notifications\n\nThere is a newer Moodle version available!\nMoodle 5.0.6+ (Build: 20260306) Version 2025041406.06 (Stable version)\nMoodle 5.1.3+ (Build: 20260306) Version 2025100603.06 (Stable version)\nMoodle 4.5.10+ (Build: 20260306) Version 2024100710.04 (Stable version)\nMoodle 4.4.12+ (Build: 20251212) Version 2024042212.01 (Stable version)\n\nSee http://127.0.0.1:8080/admin/index.php for more details\n\nIt is strongly recommended that you update your site to the latest version to obtain all recent security and bug fixes.\n\nYour Moodle site http://127.0.0.1:8080 is configured to automatically check for available updates. You are receiving this message as the administrator of the site. You can disable automatic checks for available updates in Site administration / Server / Update notifications or customise the delivery of this message via your preferences page.\n',2,'<h1>Update notifications</h1>\n<h2>There is a newer Moodle version available!</h2>\n<ul>\n<li><strong>Moodle 5.0.6+ (Build: 20260306)</strong> Version 2025041406.06 (Stable version)</li>\n<li><strong>Moodle 5.1.3+ (Build: 20260306)</strong> Version 2025100603.06 (Stable version)</li>\n<li><strong>Moodle 4.5.10+ (Build: 20260306)</strong> Version 2024100710.04 (Stable version)</li>\n<li><strong>Moodle 4.4.12+ (Build: 20251212)</strong> Version 2024042212.01 (Stable version)</li>\n</ul>\n<p>See <a href=\"http://127.0.0.1:8080/admin/index.php\">http://127.0.0.1:8080/admin/index.php</a> for more details</p>\n<p>It is strongly recommended that you update your site to the latest version to obtain all recent security and bug fixes.</p>\n<footer><p style=\"font-size:smaller; color:#333;\">Your Moodle site <a href=\"http://127.0.0.1:8080\">http://127.0.0.1:8080</a> is configured to automatically check for available updates. You are receiving this message as the administrator of the site. You can disable automatic checks for available updates in Site administration / Server / Update notifications or customise the delivery of this message via your preferences page.</p></footer>','Update notifications','moodle','availableupdate',NULL,NULL,1774716279,1773847442,NULL),
(6,-20,3,'You have upcoming activities due','Hi Ivan,\n\n<br/><br/>You have upcoming activities due:\n\nЛабораторна робота 1 is due: http://127.0.0.1:8080/report/insights/action.php?action=viewupcoming&predictionid=2&forwardurl=http%3A%2F%2F127.0.0.1%3A8080%2Fmod%2Fassign%2Fview.php%3Fid%3D3\nUseful: http://127.0.0.1:8080/report/insights/action.php?action=useful&forwardurl=http%3A%2F%2F127.0.0.1%3A8080%2Freport%2Finsights%2Fdone.php%3Factionvisiblename%3DUseful%26target%3D_blank&predictionid=2\nNot useful: http://127.0.0.1:8080/report/insights/action.php?action=notuseful&forwardurl=http%3A%2F%2F127.0.0.1%3A8080%2Freport%2Finsights%2Fdone.php%3Factionvisiblename%3DNot%2520useful%26target%3D_blank&predictionid=2\n',2,'<head><style>\nbody:not(.dir-ltr):not(.dir-rtl) {\n    font-family: \'Open Sans\', sans-serif;\n}\n.btn-insight {\n    color: #007bff;\n    background-color: transparent;\n    display: inline-block;\n    font-weight: 400;\n    text-align: center;\n    white-space: nowrap;\n    vertical-align: middle;\n    user-select: none;\n    border: 1px solid #007bff;\n    padding: .375rem .75rem;\n    line-height: 1.5;\n    border-radius: 0;\n    text-decoration: none;\n    cursor: pointer;\n}\n</style></head>\n\n    <head><style>\ntable {\n    text-align: justify;\n    margin-bottom: 1rem;\n    margin-top: 1rem;\n}\ntable tr.when {\n    background-color: #e9ecef;\n}\ntable th {\n    padding: 1rem .75rem 1rem .75rem;\n    font-weight: 400;\n    font-size: larger;\n    border-top: 1px solid #dee2e6;\n}\ntable td {\n    padding: .75rem;\n}\ntable td.link {\n    border-top: 1px solid #dee2e6;\n    border-bottom: 1px solid #dee2e6;\n}\n</style></head>\n\n<div>\n    Hi Ivan,\n\n<br/><br/>You have upcoming activities due:\n    <br/><br/>\n\n        <table class=\"table upcoming-activity-due\">\n            <thead>\n                <tr>\n                    <th scope=\"col\" class=\"h5\">\n                            <img class=\"icon \" alt=\"Activity event\" title=\"Activity event\" src=\"http://127.0.0.1:8080/theme/image.php/boost/assign/1773746936/monologo\" />\n                        Лабораторна робота 1 is due\n                    </th>\n                </tr>\n            </thead>\n            <tbody>\n                <tr class=\"when\">\n                    <td><strong>When: Tuesday, 24 March 2026, 12:00 AM</strong></td>\n                </tr>\n                <tr>\n                    <td>Course: Програмування</td>\n                </tr>\n                <tr>\n                    <td class=\"link\"><a href=\"http://127.0.0.1:8080/report/insights/action.php?action=viewupcoming&amp;predictionid=2&amp;forwardurl=http%3A%2F%2F127.0.0.1%3A8080%2Fmod%2Fassign%2Fview.php%3Fid%3D3\">Go to activity</a></td>\n                </tr>\n            </tbody>\n        </table>\n</div>\n<br/>\n\n\n    <div>\n        <strong>Was this helpful?</strong>\n        <a href=\"http://127.0.0.1:8080/report/insights/action.php?action=useful&amp;forwardurl=http%3A%2F%2F127.0.0.1%3A8080%2Freport%2Finsights%2Fdone.php%3Factionvisiblename%3DUseful%26target%3D_blank&amp;predictionid=2\" target=\"_blank\" class=\"btn-insight btn btn-outline-primary\">Yes</a>\n        <a href=\"http://127.0.0.1:8080/report/insights/action.php?action=notuseful&amp;forwardurl=http%3A%2F%2F127.0.0.1%3A8080%2Freport%2Finsights%2Fdone.php%3Factionvisiblename%3DNot%2520useful%26target%3D_blank&amp;predictionid=2\" target=\"_blank\" class=\"btn-insight btn btn-outline-primary\">No</a>\n    </div>','Hi Ivan,\n\n<br/><br/>You have upcoming activities due:\n\nЛабораторна робота 1 is due: http://127.0.0.1:8080/report/insights/action.php?action=viewupcoming&predictionid=2&forwardurl=http%3A%2F%2F127.0.0.1%3A8080%2Fmod%2Fassign%2Fview.php%3Fid%3D3\nUseful: http://127.0.0.1:8080/report/insights/action.php?action=useful&forwardurl=http%3A%2F%2F127.0.0.1%3A8080%2Freport%2Finsights%2Fdone.php%3Factionvisiblename%3DUseful%26target%3D_blank&predictionid=2\nNot useful: http://127.0.0.1:8080/report/insights/action.php?action=notuseful&forwardurl=http%3A%2F%2F127.0.0.1%3A8080%2Freport%2Finsights%2Fdone.php%3Factionvisiblename%3DNot%2520useful%26target%3D_blank&predictionid=2\n','moodle','insights','http://127.0.0.1:8080/report/insights/action.php?action=viewupcoming&predictionid=2&forwardurl=http%3A%2F%2F127.0.0.1%3A8080%2Fmod%2Fassign%2Fview.php%3Fid%3D3','You have upcoming activities due',NULL,1773847442,NULL),
